class Solution:
    def canSortArray(self, nums: List[int]) -> bool:
        # Precompute the number of set bits for each element
        set_bits = [bin(num).count('1') for num in nums]

        # Group elements by their set bit count
        groups = {}
        for i in range(len(nums)):
            bit_count = set_bits[i]
            if bit_count not in groups:
                groups[bit_count] = []
            groups[bit_count].append(nums[i])

        # For each group, sort the elements (since they can be rearranged among themselves)
        for key in groups:
            groups[key].sort()

        # Reconstruct the sorted array based on the groups
        sorted_nums = []
        for key in sorted(groups.keys()):
            sorted_nums.extend(groups[key])

        # Check if the reconstructed array matches the sorted version of the original
        return sorted_nums == sorted(nums)
